import './App.css';
import 'bootstrap/dist/css/bootstrap.min.css';
import data from './data';
import data2 from './data2';

import { useNavigate } from 'react-router-dom';

/* banner */
import { Container, Row, Col } from 'react-bootstrap';
import Carousel from 'react-bootstrap/Carousel';

import { useState, useEffect } from 'react';

/* 라우터 */
import { Route, Routes } from 'react-router-dom';
import Company from './routes/Company';
import Product from './routes/Product';
import Info from './routes/Info';
import Notice from './routes/Notice';

/* 컴포넌트 */
import Header from './component/Header';
import Footer from './component/Footer';
import Login from './page/Login';
import Mypage from './page/Mypage';
import Detail from './routes/Detail';
import Cart from './routes/Cart';


/* sass컴포넌트 */
import SassComponent from './SassComponent';
import CSSModule from './CSSModule';
import StyledComponent from './styledComponent';

// import Layout from './component/Layout';

function App() {
  let obj = {name:'shin'}
  localStorage.setItem('data',JSON.stringify(obj));
  //콘솔에서 확인
  let print = localStorage.getItem('data')
  console.log(JSON.parse(print).name);

  let [goods] = useState(data);
  let [goods2] = useState(data2);
  let navigate = useNavigate();
  function Card(props) {
    function imgClick() {
      navigate('/detail/' + props.i);
    }

    return (
      <Col>
        <img src={props.goods.img} alt="cake" width={200} onClick={imgClick} />
        <h4>{props.goods.title}</h4>
        <p>{props.goods.price}</p>
      </Col>
    );
  }
  //state를 이용하여 초기 배너 보이도록 true로 설정
  let [intro, setIntro] = useState(true); //true이면 보이고 false이면 안보이게
  useEffect(() => {
    //setTimeout을 이용해 타이머 설정하기
    let time = setTimeout(() => {
      setIntro(false); //3촣에 배너 감추기
    }, 3000);
    console.log(2);
    return () => {
      console.log(1);
      clearTimeout(time);
    };
  });
  return (
    <>
      <Header />
      {/* <Layout /> */}

      {/* 라우트페이지로 이동 */}
      <Routes>
        <Route
          path="/"
          element={
            <>
              <div>
                {/* 참일때 인트로가 보여지도록 */}
                {intro === true ? (
                  <div className="introWrap">
                    <h1>인트로페이지</h1>
                  </div>
                ) : null}{' '}
                {/* 그렇지 않으면 사라지도록 */}
              </div>
              {/* banner */}
              <Carousel>
                <Carousel.Item>
                  <div className="main-bg1"></div>
                  <Carousel.Caption>
                    <h3>First slide label</h3>
                    <p>
                      Nulla vitae elit libero, a pharetra augue mollis interdum.
                    </p>
                  </Carousel.Caption>
                </Carousel.Item>
                <Carousel.Item>
                  <div className="main-bg2"></div>
                  <Carousel.Caption>
                    <h3>Second slide label</h3>
                    <p>
                      Lorem ipsum dolor sit amet, consectetur adipiscing elit.
                    </p>
                  </Carousel.Caption>
                </Carousel.Item>
                <Carousel.Item>
                  <div className="main-bg3"></div>
                  <Carousel.Caption>
                    <h3>Third slide label</h3>
                    <p>
                      Praesent commodo cursus magna, vel scelerisque nisl
                      consectetur.
                    </p>
                  </Carousel.Caption>
                </Carousel.Item>
              </Carousel>
              <Container className="contFirst">
                <h3>NEW CAKE</h3>
                <Row>
                  {/* map반복문 사용하기 */}
                  {goods.map((a, i) => {
                    /* array안에 goods갯수만큼 반복됨. */
                    return <Card goods={goods[i]} i={i + 1} key={i} />;
                  })}
                </Row>
              </Container>
              <Container>
                <Row>
                  <Col>
                    <img src={goods2[0].img} alt="데이터이미지" />
                    <h4>{goods2[0].title}</h4>
                    <h4>{goods2[0].price}</h4>
                  </Col>
                </Row>
              </Container>

              {/* 동영상 */}
              {/* 동영상 폴더는 pubilc폴더에 넣는다. (컴파일과 빌드시 필요함) */}
              <Container fluid className="contFirst vidoWrap">
                <Row>
                  <video controls loop autoPlay muted>
                    <source src="/video/main.mp4"></source>
                  </video>
                </Row>
              </Container>
            </>
          }
        />
        <Route path="/Company" element={<Company />} />
        <Route path="/Product" element={<Product />} />
        <Route path="/Info" element={<Info />} />
        <Route path="/Product" element={<Product />} />
        <Route path="/Notice" element={<Notice />} />
        <Route path="/Login" element={<Login />} />
        <Route path="/Mypage" element={<Mypage />} />
        <Route path="/Cart" element={<Cart />} />

        <Route path="/Detail/:id" element={<Detail goods={goods} />} />

        <Route path="/SassComponent" element={<SassComponent />} />
        <Route path="/CSSModule" element={<CSSModule />} />
        <Route path="/StyledComponent" element={<StyledComponent />} />

        <Route
          path="*"
          element={
            <div style={{ marginTop: '100px' }}>
              요청하신 페이지는 없는 페이지 입니다.
            </div>
          }
        />
      </Routes>

      <Footer />
    </>
  );
}

export default App;
