/* header */
import { Container, Nav, Navbar } from 'react-bootstrap';
import 'bootstrap/dist/css/bootstrap.min.css';
import { Link, useNavigate } from 'react-router-dom';

const Header = () => {
  let navigate = useNavigate();
  return (
    <>
      {/* header  */}
      <Navbar collapseOnSelect expand="lg" bg="dark" variant="dark" id="header">
        <Container>
          <Navbar.Brand href="https://jellyzoo.github.io">
            <img
              src="../img/logo.png"
              alt="logo"
              width={200}
              className="mt-15"
            />
          </Navbar.Brand>
          <Navbar.Toggle aria-controls="responsive-navbar-nav" />
          <Navbar.Collapse id="responsive-navbar-nav">
            <Nav className="me-auto">
              <Link to="https://jellyzoo.github.io/Company" className="navText">
                카페파스쿠찌
              </Link>

              <Link to="https://jellyzoo.github.io/Info" className="navText">
                매장안내
              </Link>
              <Link to="https://jellyzoo.github.io/Notice" className="navText">
                공지사항
              </Link>
              <Link to="https://jellyzoo.github.io/Cart" className="navText">
                장바구니
              </Link>
            </Nav>
            <Nav>
              <Link to="https://jellyzoo.github.io/login" className="navText">
                login
              </Link>
              <Link to="https://jellyzoo.github.io/login" className="navText">
                mypage
              </Link>
            </Nav>
          </Navbar.Collapse>
        </Container>
      </Navbar>
    </>
  );
};

export default Header;
